import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace, createForks } from "@tigrisdata/agent-kit";
import { put, get } from "@tigrisdata/storage";

async function main() {
  const trialIdRaw = await readFile("/logs/artifacts/trial_id", "utf-8");
  const trialId = trialIdRaw.trim().toLowerCase().replace(/[^a-z0-9.-]/g, "-");

  const workspaceName = `harbor-ro-${trialId}`;

  console.log(`Creating workspace: ${workspaceName}`);
  const { data: editorData, error: editorError } = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    enableSnapshots: true,
    credentials: { role: "Editor" }
  });

  if (editorError || !editorData || !editorData.credentials) {
    console.error("Failed to create editor workspace:", editorError);
    process.exit(1);
  }

  const editorCreds = editorData.credentials;
  const editorBucket = editorData.bucketName;

  console.log(`Editor workspace created. Bucket: ${editorBucket}`);

  const putEditorRes = await put("notes/welcome.txt", "hello readonly", {
    config: {
      bucket: editorBucket,
      accessKeyId: editorCreds.accessKeyId,
      secretAccessKey: editorCreds.secretAccessKey
    }
  });

  if (putEditorRes.error) {
    console.error("Failed to write welcome.txt with editor credentials:", putEditorRes.error);
    process.exit(1);
  }

  console.log("Wrote welcome.txt with editor credentials.");

  const forkPrefix = `harbor-ro-${trialId}-readonly`;
  console.log(`Creating fork with prefix: ${forkPrefix}`);

  const { data: forkSet, error: forkError } = await createForks(editorBucket, 1, {
    prefix: forkPrefix,
    credentials: { role: "ReadOnly" }
  });

  if (forkError || !forkSet || !forkSet.forks || forkSet.forks.length === 0 || !forkSet.forks[0].credentials) {
    console.error("Failed to create fork:", forkError);
    process.exit(1);
  }

  const forkBucket = forkSet.forks[0].bucketName;
  const readonlyCreds = forkSet.forks[0].credentials;

  console.log(`Fork created. Bucket: ${forkBucket}`);

  console.log("Attempting to write forbidden.txt with readonly credentials...");
  const putReadonlyRes = await put("notes/forbidden.txt", "should be rejected", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey
    }
  });

  if (!putReadonlyRes.error) {
    console.error("Expected write with readonly credentials to fail, but it succeeded.");
    process.exit(1);
  }

  console.log("Write with readonly credentials failed as expected.");

  const err = putReadonlyRes.error;
  const errStr = JSON.stringify(err, Object.getOwnPropertyNames(err));
  const denialStr = `${err.name ?? "Error"}: ${err.message ?? String(err)} - Details: ${errStr}`;

  await writeFile("/home/user/tigris-task/write-denial.log", denialStr, "utf-8");
  console.log("Wrote write-denial.log.");

  console.log("Attempting to read welcome.txt with readonly credentials...");
  const getReadonlyRes = await get("notes/welcome.txt", "string", {
    config: {
      bucket: forkBucket,
      accessKeyId: readonlyCreds.accessKeyId,
      secretAccessKey: readonlyCreds.secretAccessKey
    }
  });

  if (getReadonlyRes.error || getReadonlyRes.data === undefined) {
    console.error("Failed to read welcome.txt with readonly credentials:", getReadonlyRes.error);
    process.exit(1);
  }

  console.log("Successfully read welcome.txt with readonly credentials.");
  await writeFile("/home/user/tigris-task/readback.txt", getReadonlyRes.data, "utf-8");
  console.log("Wrote readback.txt.");

  console.log("All steps completed successfully.");
}

main().catch(err => {
  console.error("Unhandled error:", err);
  process.exit(1);
});

