    credentialProvider?: () => Promise<{
        accessKeyId: string;
        secretAccessKey: string;
        sessionToken?: string;
        expiration?: Date;
    }>;
};
type TigrisConfig = TigrisEndpointsConfig & TigrisAuthConfig;

/**
 * Unified configuration for Tigris Agentic operations.
 * Accepted directly by both `@tigrisdata/storage` and `@tigrisdata/iam`.
 * When omitted, the underlying SDKs fall back to environment variables.
 */
type TigrisAgentKitConfig = TigrisConfig;

type CheckpointOptions = {
    /** Optional name for the checkpoint snapshot. */
    name?: string;
    config?: TigrisAgentKitConfig;
};
type Checkpoint = {
    snapshotId: string;
    name?: string;
    createdAt?: Date;
};
type RestoreOptions = {
    /** Name for the restored fork bucket. Defaults to `${bucket}-restore-${timestamp}`. */
    forkName?: string;
    config?: TigrisAgentKitConfig;
};
