async function waitAndCreate() {
  const workspaceName = "harbor-ro-readonly-workspace-write-denial--asbtlqf";
  while (true) {
    console.log("Trying to create...");
    const { data, error } = await createWorkspace(workspaceName, {
      ttl: { days: 1 },
      enableSnapshots: true,
      credentials: { role: "Editor" }
